    public function run(): void
    {
        $maxCode = (int) ThematicCategory::pluck('code')->map(fn ($c) => (int) $c)->max();
        $extra = $this->extraRows();
        foreach ($extra as &$row) {
            $existing = ThematicCategory::where('name', $row['name'])->first();
            if ($existing) {
                $row['code'] = $existing->code;
            } else {
                $maxCode++;
                $row['code'] = (string) $maxCode;
            }
        }
        unset($row);

        $rows = array_merge($this->rows(), $extra);
        $roots = array_filter($rows, fn ($r) => $r['parent_code'] === null);
        $children = array_filter($rows, fn ($r) => $r['parent_code'] !== null);

        foreach ($roots as $row) {
            ThematicCategory::updateOrCreate(
                ['code' => $row['code']],
                [
                    'name' => $row['name'],
                    'is_active' => true,
                    'parent_id' => null,
                    'description' => $row['description'] ?? null,
                    'keywords' => $row['keywords'] ?? null,
                ]
            );
        }

        foreach ($children as $row) {
            $parent = ThematicCategory::where('code', $row['parent_code'])->first();
            ThematicCategory::updateOrCreate(
                ['code' => $row['code']],
                [
                    'name' => $row['name'],
                    'is_active' => true,
                    'parent_id' => $parent?->id,
                    'description' => $row['description'] ?? null,
                    'keywords' => $row['keywords'] ?? null,
                ]
            );
        }
    }
